// 可以看全部案件的位階
const CAN_SEE_ALL = ["developer","principal","exec_director","design_director","construction_director","design_manager","manager"];
// 開發人員判斷
function isDeveloper(user, devMode = true) { return user?.email === DEVELOPER_EMAIL && devMode; }
// 可以編輯案件的判斷
function canEditProject(user, project, devMode = true) {
  if (!user) return false;
  if (isDeveloper(user, devMode)) return true;
  if (project.designer === user.name) return true;
  if (project.projectManager === user.name) return true;
  if (project.ownerEmail === user.email) return true;
  if (project.siteManager === user.name) return true;
  if (!project.designer) return true;
  return false;
}
// 可以看到案件的判斷
function canSeeProject(user, project, devMode = true) {
  if (!user) return false;
  if (isDeveloper(user, devMode)) return true;
  if (user.role && CAN_SEE_ALL.includes(user.role)) return true;
  if (project.designer === user.name) return true;
  if (project.projectManager === user.name) return true;
  if (project.ownerEmail === user.email) return true;
  if (project.assistant === user.name) return true;
  if (project.siteManager === user.name) return true;
  return false;
}

// 簡單密碼雜湊（不用後端也能比對）
async function hashPassword(password) {
  const msgBuffer = new TextEncoder().encode(password + "mudao_salt_2024");
  const hashBuffer = await crypto.subtle.digest("SHA-256", msgBuffer);
  const hashArray = Array.from(new Uint8Array(hashBuffer));
  return hashArray.map(b => b.toString(16).padStart(2, "0")).join("");
}

// ── 雲端案件操作 ──
// v30 修復：改用 PostgREST upsert（on_conflict=owner_email,project_id）
// 需要 Supabase 表 projects 的 PRIMARY KEY 是 (owner_email, project_id) 複合主鍵
async function cloudSaveProject(project, ownerEmail) {
  try {
    const payload = {
      owner_email: ownerEmail,
      project_id: project.id,
      data: JSON.stringify(project),
      updated_at: new Date().toISOString(),
    };
    const res = await sbFetch("projects?on_conflict=owner_email,project_id", {
      method: "POST",
      headers: { "Prefer": "return=representation,resolution=merge-duplicates" },
      body: JSON.stringify(payload),
    });
    // upsert 成功會回傳該筆 row 的陣列；失敗才回 []
    if (Array.isArray(res) && res.length > 0) return true;
    console.error("雲端儲存：upsert 沒有回傳資料，可能 schema 主鍵未調整為 (owner_email, project_id)");
    return false;
  } catch (e) { console.error("雲端儲存失敗:", e); return false; }
}

async function cloudDeleteProject(projectId, ownerEmail) {
  try {
    await sbFetch(`projects?owner_email=eq.${encodeURIComponent(ownerEmail)}&project_id=eq.${projectId}`, { method: "DELETE" });
    return true;
  } catch (e) { console.error("雲端刪除失敗:", e); return false; }
}

async function cloudLoadProjects(currentUser, allUsers, devMode = true) {
  try {
    const data = await sbFetch("projects?select=*&order=updated_at.desc");
    if (!Array.isArray(data)) return [];
    const projects = data.map(row => {
      try { return JSON.parse(row.data); } catch { return null; }
    }).filter(Boolean);
    return projects.filter(p => canSeeProject(currentUser, p, devMode));
  } catch (e) { console.error("雲端載入失敗:", e); return []; }
}

async function sbFetch(path, options = {}) {
  try {
    // v31 修復：把 headers 從 options 抽出來分開合併，避免 ...options 把 apikey/Authorization 整組蓋掉
    const { headers: customHeaders, ...restOptions } = options;
    const res = await fetch(`${SUPABASE_URL}/rest/v1/${path}`, {
      ...restOptions,
      headers: {
        "apikey": SUPABASE_KEY,
        "Authorization": `Bearer ${SUPABASE_KEY}`,
        "Content-Type": "application/json",
        "Prefer": "return=representation",
        ...(customHeaders || {}),
      },
    });
    if (res.status === 204) return [];
    const text = await res.text();
    if (!text) return [];
    try { return JSON.parse(text); } catch { return []; }
  } catch (e) {
    console.error("Supabase 連線失敗:", e);
    return [];
  }
}

