function getDailyTitle(email, startDate) {
  const tenure = calcTenure(startDate);
  if (!tenure) return null;
  const level = getTenureLevel(tenure.days);
  const categories = Object.keys(TITLES[level]);
  const today = new Date();
  const dayOfYear = Math.floor((today - new Date(today.getFullYear(), 0, 0)) / 86400000);
  const catIdx = dayOfYear % categories.length;
  const cat = categories[catIdx];
  const titles = TITLES[level][cat];
  const titleIdx = (dayOfYear + email.length) % titles.length;
  return { level, title: titles[titleIdx], category: cat };
}

