function getDailyFortune(projects, currentUser) {
  const today = new Date();
  const seed = today.getFullYear() * 10000 + (today.getMonth() + 1) * 100 + today.getDate() + (currentUser?.email?.length || 0);

  // 運勢等級
  const fortuneIdx = seed % FORTUNE_LEVELS.length;
  const fortune = FORTUNE_LEVELS[fortuneIdx];
  const descIdx = (seed * 3) % fortune.desc.length;

  // 案件壓力分析
  const pressureProjects = [];
  projects.forEach(p => {
    if (p.stage === "提案中" && p.consultDate) {
      const result = getRemainingWorkDays(p.consultDate, 15);
      if (result && !p.proposalDate && result.remaining <= 5) {
        pressureProjects.push({ name: p.name, reason: `提案剩 ${result.remaining} 天` });
      }
    }
    if (p.stage === "已簽約") {
      const lastMeeting = (p.signedMeetingDates || []).filter(m => m.start).slice(-1)[0];
      if (lastMeeting) {
        const result = getRemainingWorkDays(lastMeeting.start, 10);
        if (result && result.remaining <= 4) {
          pressureProjects.push({ name: p.name, reason: `交件剩 ${result.remaining} 天` });
        }
      }
    }
    if (p.stage === "施工中" && p.progress === 0 && p.startDate) {
      pressureProjects.push({ name: p.name, reason: "施工進度 0%，需要更新" });
    }
  });

  const pressureLevel = pressureProjects.length === 0 ? "低" : pressureProjects.length <= 2 ? "中" : "高";
  const pressureColor = pressureProjects.length === 0 ? "#50c878" : pressureProjects.length <= 2 ? "#f0a850" : "#e05b5b";

  // 財運
  const totalPending = projects.filter(p => p.stage === "施工中" || p.stage === "已簽約")
    .reduce((s, p) => s + (parseFloat(p.budget) || 0), 0);

  // 今日建議
  const advices = [
    "先處理最燙手的案子，其他的交給宇宙。",
    "今天適合打幾通電話給久未聯繫的廠商。",
    "把那個一直拖著的圖面，今天就完成它。",
    "跟客戶確認一個小細節，可以避免大麻煩。",
    "整理一下報價單，數字清楚心情好。",
    "休息一下再繼續，靈感在咖啡裡。",
    "今天不要改超過三次，第四次通常更差。",
    "先把簡單的事做完，複雜的會變容易。",
  ];
  const adviceIdx = (seed * 7) % advices.length;

  // 總評價
  const ratings = pressureProjects.length === 0 && fortune.level === "大吉"
    ? { text: "今日滿分設計師！所有案件進度超前，繼續衝！", emoji: "🔥", color: "#f0d050" }
    : pressureProjects.length >= 3
    ? { text: "今日壓力山大，但你撐過來了，明天會更好！", emoji: "💪", color: "#5b8af0" }
    : pressureProjects.length >= 1
    ? { text: `今日中等發揮，有 ${pressureProjects.length} 件案子需要關注，加把勁！`, emoji: "⚡", color: "#f0a850" }
    : { text: "今日平穩順暢，繼續保持好節奏！", emoji: "✨", color: "#50c878" };

  return { fortune, descIdx, pressureProjects, pressureLevel, pressureColor, totalPending, advice: advices[adviceIdx], rating: ratings };
}

