function isHolidayToday() {
  const today = new Date();
  const day = today.getDay(); // 0=日, 6=六
  if (day === 0 || day === 6) return true;
  const dateStr = today.toISOString().split("T")[0];
  return TW_HOLIDAYS.has(dateStr);
}

