// ── 全局錯誤邊界 ──
function ErrorBoundary({ children }) {
  const [error, setError] = useState(null);
  useEffect(() => {
    const handler = (e) => {
      console.error("全局錯誤:", e.error);
      setError((e.error?.stack || e.error?.message || String(e.error)).slice(0, 300));
    };
    const phandler = (e) => {
      console.error("Promise錯誤:", e.reason);
      setError((e.reason?.stack || e.reason?.message || String(e.reason)).slice(0, 300));
    };
    window.addEventListener("error", handler);
    window.addEventListener("unhandledrejection", phandler);
    return () => { window.removeEventListener("error", handler); window.removeEventListener("unhandledrejection", phandler); };
  }, []);
  if (error) return (
    <div style={{ minHeight: "100vh", background: "#080810", display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", padding: 24, fontFamily: "sans-serif" }}>
      <div style={{ fontSize: 40, marginBottom: 16 }}>⚠️</div>
      <div style={{ fontSize: 16, color: "#f0ead8", fontWeight: 700, marginBottom: 8 }}>App 發生錯誤</div>
      <div style={{ fontSize: 11, color: "#555", marginBottom: 24, textAlign: "left", background: "#0f0f1a", padding: 12, borderRadius: 8, maxWidth: 340, wordBreak: "break-all", whiteSpace: "pre-wrap" }}>{error}</div>
      <button onClick={() => { try { localStorage.clear(); } catch {} window.location.reload(); }}
        style={{ background: "#5b8af0", border: "none", borderRadius: 12, padding: "12px 24px", color: "white", fontSize: 14, fontWeight: 700, cursor: "pointer", marginBottom: 12 }}>
        🔄 清除資料並重新載入
      </button>
      <button onClick={() => setError(null)}
        style={{ background: "rgba(255,255,255,0.08)", border: "none", borderRadius: 12, padding: "10px 20px", color: "#888", fontSize: 13, cursor: "pointer" }}>
        嘗試繼續使用
      </button>
    </div>
  );
  return children;
}

